import type {
  InterruptStudioChatResponse,
  ListStudioChatMessagesResponse,
  StudioChatStreamEvent,
} from "server";
import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
import { toast } from "sonner";
import { api, apiBaseUrl } from "./client";
import { projectKeys } from "./keys";

export const useListMessages = (projectId: string) =>
  useQuery({
    queryKey: projectKeys.messages(projectId),
    queryFn: async () =>
      (
        await api.get<ListStudioChatMessagesResponse>(
          `/api/projects/${projectId}/messages`,
        )
      ).data,
    staleTime: Infinity,
    refetchOnMount: false,
    refetchOnWindowFocus: false,
  });

type SendChatPayload = {
  projectId: string;
  message: string;
  onEvent?: (event: StudioChatStreamEvent) => void;
};

export const useSendChatMessage = () => {
  const queryClient = useQueryClient();

  return useMutation({
    // Shows its own error toasts below (raw fetch + stream events), so opt out
    // of the global API error toast to avoid double toasts.
    meta: { skipGlobalErrorToast: true },
    mutationFn: async ({ projectId, message, onEvent }: SendChatPayload) => {
      const response = await fetch(
        `${apiBaseUrl}/api/projects/${projectId}/chat`,
        {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ message }),
        },
      );

      if (!response.ok || !response.body) {
        const error = (await response.json().catch(() => null)) as {
          error?: string;
          message?: string;
        } | null;
        toast.error(error?.error ?? "Something went wrong", {
          description: error?.message,
        });
        throw new Error(error?.message ?? "Chat request failed");
      }

      const reader = response.body.getReader();
      const decoder = new TextDecoder();
      let buffer = "";
      let finalText = "";
      let interrupted = false;

      const readLine = (line: string) => {
        const event = JSON.parse(line) as StudioChatStreamEvent;
        onEvent?.(event);

        if (event.type === "assistant") {
          finalText = event.text;
        } else if (event.type === "interrupted") {
          interrupted = true;
        } else if (event.type === "error") {
          toast.error("Agent error", { description: event.message });
          throw new Error(event.message);
        }
      };

      for (;;) {
        const { done, value } = await reader.read();
        buffer += value
          ? decoder.decode(value, { stream: !done })
          : decoder.decode();

        let newlineIndex = buffer.indexOf("\n");
        while (newlineIndex >= 0) {
          const line = buffer.slice(0, newlineIndex).trim();
          buffer = buffer.slice(newlineIndex + 1);
          if (line) readLine(line);
          newlineIndex = buffer.indexOf("\n");
        }

        if (done) break;
      }

      const lastLine = buffer.trim();
      if (lastLine) readLine(lastLine);

      if (!finalText && !interrupted) {
        throw new Error("The agent returned an empty response");
      }

      return { content: finalText, interrupted };
    },
    onSettled: (_data, _error, { projectId }) => {
      void queryClient.invalidateQueries({
        queryKey: projectKeys.messages(projectId),
      });
    },
  });
};

export const useInterruptChat = () =>
  useMutation({
    mutationFn: async ({ projectId }: { projectId: string }) =>
      (
        await api.post<InterruptStudioChatResponse>(
          `/api/projects/${projectId}/chat/interrupt`,
        )
      ).data,
  });

import {
  foreignKey,
  index,
  pgTable,
  primaryKey,
  serial,
  text,
  timestamp,
  unique,
  uuid,
} from "drizzle-orm/pg-core";

export const studioProjects = pgTable(
  "studio_projects",
  {
    projectId: uuid("project_id").defaultRandom().notNull(),
    projectName: text("project_name").notNull(),
    e2bSandboxId: text("e2b_sandbox_id").notNull(),
    createdAt: timestamp("created_at", { withTimezone: true })
      .defaultNow()
      .notNull(),
  },
  table => [
    primaryKey({
      name: "studio_projects_pkey",
      columns: [table.projectId],
    }),
  ],
);

export const studioProjectSessions = pgTable(
  "studio_project_sessions",
  {
    sessionId: serial("session_id").notNull(),
    projectId: uuid("project_id").notNull(),
    // Claude Code session id: captured from the first run's init event and
    // replayed via `--resume` on later turns. Null until the first agent run.
    // Also locates the transcript when chat history is rebuilt from the sandbox.
    claudeSessionId: text("claude_session_id"),
    createdAt: timestamp("created_at", { withTimezone: true })
      .defaultNow()
      .notNull(),
  },
  table => [
    primaryKey({
      name: "studio_project_sessions_pkey",
      columns: [table.sessionId],
    }),
    foreignKey({
      name: "studio_project_sessions_project_id_fk",
      columns: [table.projectId],
      foreignColumns: [studioProjects.projectId],
    }),
    unique("studio_project_sessions_claude_session_id_key").on(
      table.claudeSessionId,
    ),
    index("studio_project_sessions_project_id_created_at_idx").on(
      table.projectId,
      table.createdAt,
    ),
  ],
);

