1	import "dotenv/config";
2	import express, { type ErrorRequestHandler } from "express";
3	import cors from "cors";
4	import { env } from "./env";
5	import { projectsRouter } from "./routes/projects/index";
6	
7	const app = express();
8	
9	const corsOrigin =
10	  env.WEB_ORIGIN === "*"
11	    ? true
12	    : env.WEB_ORIGIN.split(",").map(origin => origin.trim());
13	
14	app.use(cors({ origin: corsOrigin }));
15	app.use(express.json({ limit: "10mb" }));
16	
17	app.get("/health", (_req, res) => {
18	  res.json({ ok: true });
19	});
20	
21	app.use("/api/projects", projectsRouter);
22	
23	const errorMiddleware: ErrorRequestHandler = (error, req, res, _next) => {
24	  // eslint-disable-next-line no-console
25	  console.error(`[error] ${req.method} ${req.originalUrl}`, error);
26	  if (res.headersSent) return;
27	  res.status(500).json({
28	    error: "Internal Server Error",
29	    message: "Something went wrong",
30	  });
31	};
32	
33	app.use(errorMiddleware);
34	
35	app.listen(env.PORT, () => {
36	  // eslint-disable-next-line no-console
37	  console.log(`Studio server running on http://localhost:${env.PORT}`);
38	});
