1	import type { ReactNode } from "react";
2	import { useEffect, useRef, useState } from "react";
3	import { ArrowUp, Check, Loader2, Square, X } from "lucide-react";
4	import Markdown from "react-markdown";
5	import remarkGfm from "remark-gfm";
6	import type { StudioChatMessage } from "server";
7	import { Button } from "../components/ui/button";
8	import { Textarea } from "../components/ui/textarea";
9	import {
10	  useInterruptChat,
11	  useListMessages,
12	  useSendChatMessage,
13	} from "../api/chat";
14	
15	type ChatStep = {
16	  id: string;
17	  label: string;
18	  detail?: string;
19	  status: "running" | "completed" | "failed";
20	};
21	
22	type StreamingTurn = {
23	  userText: string;
24	  assistantText: string;
25	  steps: ChatStep[];
26	  status: "running" | "interrupted";
27	};
