29	export const ChatPanel = ({ projectId }: { projectId: string }) => {
30	  const [draft, setDraft] = useState("");
31	  const [messages, setMessages] = useState<StudioChatMessage[]>([]);
32	  const [turn, setTurn] = useState<StreamingTurn | null>(null);
33	  const [elapsed, setElapsed] = useState(0);
34	  const scrollRef = useRef<HTMLDivElement | null>(null);
35	
36	  const { data: loadedMessages, isPending } = useListMessages(projectId);
37	  const sendMessage = useSendChatMessage();
38	  const interruptChat = useInterruptChat();
39	  const sending = sendMessage.isPending;
40	
41	  useEffect(() => {
42	    if (loadedMessages) setMessages(loadedMessages);
43	  }, [loadedMessages]);
44	
45	  useEffect(() => {
46	    scrollRef.current?.scrollTo({
47	      top: scrollRef.current.scrollHeight,
48	      behavior: "smooth",
49	    });
50	  }, [messages, turn]);
51	
52	  useEffect(() => {
53	    if (!sending) return;
54	    setElapsed(0);
55	    const startedAt = Date.now();
56	    const intervalId = window.setInterval(() => {
57	      setElapsed(Math.floor((Date.now() - startedAt) / 1000));
58	    }, 1000);
59	    return () => window.clearInterval(intervalId);
60	  }, [sending]);
61	
62	  const submit = () => {
63	    const message = draft.trim();
64	    if (!message || sending || isPending) return;
65	
66	    setDraft("");
67	    setTurn({ userText: message, assistantText: "", steps: [], status: "running" });
68	
69	    sendMessage.mutate(
70	      {
71	        projectId,
72	        message,
73	        onEvent: event => {
74	          if (event.type === "assistant") {
75	            setTurn(current =>
76	              current ? { ...current, assistantText: event.text } : current,
77	            );
78	          } else if (event.type === "interrupted") {
79	            setTurn(current =>
80	              current ? { ...current, status: "interrupted" } : current,
81	            );
82	          } else if (event.type === "step") {
83	            const step: ChatStep = {
84	              id: event.id,
85	              label: event.label,
86	              detail: event.detail,
87	              status: event.status,
88	            };
89	            setTurn(current => {
90	              if (!current || current.assistantText) return current;
91	              return { ...current, steps: upsertStep(current.steps, step) };
92	            });
93	          }
94	        },
95	      },
96	      {
97	        onSuccess: ({ content }) => {
98	          setTurn(null);
99	          if (content) {
100	            const now = new Date().toISOString();
101	            setMessages(current => [
102	              ...current,
103	              {
104	                id: `local-user-${Date.now()}`,
105	                role: "user",
106	                content: message,
107	                createdAt: now,
108	              },
109	              {
110	                id: `local-assistant-${Date.now()}`,
111	                role: "assistant",
112	                content,
113	                createdAt: now,
114	              },
115	            ]);
116	          }
117	        },
118	        onError: () => {
119	          setTurn(null);
120	          setDraft(message);
121	        },
122	      },
123	    );
124	  };
125	
126	  const showEmptyState =
127	    !isPending && messages.length === 0 && !turn;
128	
129	  return (
130	    <div className="flex flex-1 flex-col overflow-hidden">
131	      <div ref={scrollRef} className="flex-1 overflow-y-auto px-4 py-4">
132	        <div className="mx-auto flex max-w-2xl flex-col gap-5">
133	          {isPending ? (
134	            <Centered>
135	              <Loader2 className="size-4 animate-spin" />
136	              Loading messages…
137	            </Centered>
138	          ) : null}
139	
140	          {showEmptyState ? (
141	            <Centered>
142	              No messages yet. Ask the agent to build something.
143	            </Centered>
144	          ) : null}
145	
146	          {messages.map(message => (
147	            <MessageBubble key={message.id} message={message} />
148	          ))}
149	
150	          {turn ? <StreamingTurnView turn={turn} elapsed={elapsed} /> : null}
151	        </div>
152	      </div>
153	
154	      <div className="mx-auto w-full max-w-2xl px-4 pb-4">
155	        <div className="rounded-lg border border-input bg-background p-3">
156	          <Textarea
157	            value={draft}
158	            placeholder="Message the agent…"
159	            disabled={isPending}
160	            onChange={event => setDraft(event.target.value)}
161	            onKeyDown={event => {
162	              if (event.key === "Enter" && !event.shiftKey) {
163	                event.preventDefault();
164	                submit();
165	              }
166	            }}
167	            className="max-h-40 min-h-8 resize-none border-0 p-0 shadow-none focus-visible:ring-0"
168	          />
