241	            <span className="flex items-center gap-2">
242	              <Loader2 className="size-4 animate-spin" />
243	              Working…
244	            </span>
245	            <span className="tabular-nums">{formatElapsed(elapsed)}</span>
246	          </div>
247	          {turn.steps.length > 0 ? (
248	            <div className="rounded-md border border-border bg-muted/30 p-2">
249	              {turn.steps.map(step => (
250	                <StepRow key={step.id} step={step} />
251	              ))}
252	            </div>
253	          ) : null}
254	        </div>
255	      )}
256	    </div>
257	  </>
258	);
259	
260	const StepRow = ({ step }: { step: ChatStep }) => (
261	  <div className="flex min-h-7 items-start gap-2 py-1">
262	    {step.status === "running" ? (
263	      <Loader2 className="mt-0.5 size-3.5 shrink-0 animate-spin text-muted-foreground" />
264	    ) : step.status === "failed" ? (
265	      <X className="mt-0.5 size-3.5 shrink-0 text-muted-foreground" />
266	    ) : (
267	      <Check className="mt-0.5 size-3.5 shrink-0 text-muted-foreground" />
268	    )}
269	    <div className="min-w-0">
270	      <div className="truncate text-foreground">{step.label}</div>
271	      {step.detail ? (
272	        <div className="truncate text-xs text-muted-foreground">
273	          {step.detail}
274	        </div>
275	      ) : null}
276	    </div>
277	  </div>
278	);
279	
280	const AssistantMarkdown = ({ content }: { content: string }) => (
281	  <Markdown remarkPlugins={[remarkGfm]}>{content}</Markdown>
282	);
283	
284	const Centered = ({ children }: { children: ReactNode }) => (
285	  <div className="flex min-h-32 items-center justify-center gap-2 px-6 text-center text-sm text-muted-foreground">
286	    {children}
287	  </div>
288	);
289	
290	const upsertStep = (steps: ChatStep[], next: ChatStep) => {
291	  const index = steps.findIndex(step => step.id === next.id);
292	  if (index < 0) return [...steps, next];
293	  const updated = [...steps];
294	  updated[index] = next;
295	  return updated;
296	};
297	
298	const formatElapsed = (seconds: number) => {
299	  if (seconds < 60) return `${seconds}s`;
300	  const minutes = Math.floor(seconds / 60);
301	  return `${minutes}m ${(seconds % 60).toString().padStart(2, "0")}s`;
302	};
