import { useState } from "react";
import { Link, useParams } from "@tanstack/react-router";
import { ArrowLeft, Check, Copy } from "lucide-react";
import { Button } from "../components/ui/button";
import { useGetProject } from "../api/projects";
import { ChatPanel } from "./chat-panel";

export const ProjectDetailPage = () => {
  const { projectId } = useParams({ from: "/projects/$projectId" });
  const { data: project, isError } = useGetProject(projectId);

  if (isError) {
    return (
      <div className="flex min-h-screen flex-col items-center justify-center gap-4 p-8 text-sm text-muted-foreground">
        Studio project not found.
        <Button asChild variant="outline">
          <Link to="/">Back to projects</Link>
        </Button>
      </div>
    );
  }

  return (
    <div className="flex h-screen flex-col overflow-hidden">
      <header className="flex h-12 shrink-0 items-center gap-3 border-b border-border px-3">
        <Button asChild variant="ghost" size="icon" className="size-8">
          <Link to="/" aria-label="Back to projects">
            <ArrowLeft className="size-4" />
          </Link>
        </Button>
        <h1 className="truncate text-sm font-medium">
          {project?.projectName ?? "Loading…"}
        </h1>
        {project ? <SandboxBadge sandboxId={project.e2bSandboxId} /> : null}
      </header>

      <div className="flex min-h-0 flex-1 overflow-hidden">
        <div className="flex min-w-80 basis-1/3 flex-col overflow-hidden border-r border-border">
          {project ? (
            <ChatPanel projectId={projectId} />
          ) : (
            <div className="flex flex-1 items-center justify-center text-sm text-muted-foreground">
              Loading…
            </div>
          )}
        </div>

        <div className="flex min-h-0 flex-1 items-center justify-center bg-muted/20 p-6">
          <div className="text-center text-sm">
            <p className="font-medium text-foreground">Preview</p>
            <p className="text-muted-foreground">
              Coming soon — the right panel is a placeholder.
            </p>
          </div>
        </div>
      </div>
    </div>
  );
};

const SandboxBadge = ({ sandboxId }: { sandboxId: string }) => {
  const [copied, setCopied] = useState(false);

  return (
    <div className="ml-auto flex items-center gap-1.5 text-xs text-muted-foreground">
      <span className="shrink-0">Sandbox</span>
      <span
        className="max-w-64 truncate font-mono text-foreground"
        title={sandboxId}
      >
        {sandboxId}
      </span>
      <button
        type="button"
        aria-label="Copy sandbox id"
        title="Copy"
        className="rounded p-1 transition-colors hover:bg-muted"
        onClick={async () => {
          await navigator.clipboard.writeText(sandboxId);
          setCopied(true);
          window.setTimeout(() => setCopied(false), 1500);
        }}
      >
        {copied ? <Check className="size-3.5" /> : <Copy className="size-3.5" />}
      </button>
    </div>
  );
};

import { useState } from "react";
import { useNavigate } from "@tanstack/react-router";
import { Button } from "../components/ui/button";
import { useListProjects } from "../api/projects";
import { CreateProjectDialog } from "./create-project-dialog";

export const ProjectsListPage = () => {
  const { data, isPending } = useListProjects();
  const navigate = useNavigate();
  const [dialogOpen, setDialogOpen] = useState(false);

  return (
    <div className="mx-auto flex min-h-screen max-w-5xl flex-col gap-6 p-8">
      <div className="flex items-center justify-between">
        <h1 className="text-3xl font-bold tracking-tight">Studio</h1>
        <Button onClick={() => setDialogOpen(true)}>Create Project</Button>
      </div>

      <div className="overflow-hidden rounded-lg border border-border">
        <table className="w-full text-sm">
          <thead className="bg-muted/40 text-left text-muted-foreground">
            <tr>
              <th className="px-4 py-3 font-medium">Name</th>
              <th className="px-4 py-3 font-medium">Created</th>
            </tr>
          </thead>
          <tbody>
            {isPending ? (
              <tr>
                <td
                  colSpan={2}
                  className="px-4 py-10 text-center text-muted-foreground"
                >
                  Loading…
                </td>
              </tr>
            ) : data && data.length > 0 ? (
              data.map(project => (
                <tr
                  key={project.projectId}
                  className="cursor-pointer border-t border-border hover:bg-muted/40"
                  onClick={() =>
                    navigate({
                      to: "/projects/$projectId",
                      params: { projectId: project.projectId },
                    })
                  }
                >
                  <td className="px-4 py-3 font-medium">
                    {project.projectName}
                  </td>
                  <td className="px-4 py-3 text-muted-foreground">
                    {new Date(project.createdAt).toLocaleDateString()}
                  </td>
                </tr>
              ))
            ) : (
              <tr>
                <td
                  colSpan={2}
                  className="px-4 py-10 text-center text-muted-foreground"
                >
                  No projects yet. Create one to get started.
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>

      <CreateProjectDialog open={dialogOpen} onOpenChange={setDialogOpen} />
    </div>
  );
};

import "dotenv/config";
import { Template, defaultBuildLogger } from "e2b";

// Builds the E2B sandbox template used by every studio project. Run manually:
//   pnpm build:studio-template            (from apps/server)
//   pnpm --filter server build:studio-template   (from the repo root)
//
// The template ships Node + pnpm + the Claude Code CLI, with a minimal Vite
// React app at /home/user/project that the agent edits. Claude Code itself
// authenticates at runtime via the ANTHROPIC_API_KEY passed into each command.

const e2bApiKey = process.env.E2B_API_KEY?.trim();
if (!e2bApiKey) {
  throw new Error("E2B_API_KEY is required to build the studio template");
}

const template = Template({
  fileContextPath: ".",
  fileIgnorePatterns: ["**/node_modules/**", "**/dist/**"],
})
  .fromImage("node:22")
  .runCmd("corepack enable", { user: "root" })
  .runCmd("corepack prepare pnpm@10.1.0 --activate", { user: "root" })
  .runCmd("npm install -g @anthropic-ai/claude-code@latest", { user: "root" })
  .copy("project-scaffold", "/home/user/project")
  .runCmd("chown -R user:user /home/user/project", { user: "root" })
  .setWorkdir("/home/user/project")
  .runCmd("node --version && pnpm --version && claude --version", {
    user: "user",
  })
  .runCmd("pnpm install", { user: "user" })
  .setWorkdir("/home/user/project");

const buildInfo = await Template.build(template, "claude-studio", {
  apiKey: e2bApiKey,
  cpuCount: 2,
  memoryMB: 4096,
  onBuildLogs: defaultBuildLogger(),
});

// eslint-disable-next-line no-console
console.log(
  `Built E2B template ${buildInfo.name} with build ID ${buildInfo.buildId}`,
);

export const App = () => {
  return (
    <main className="app">
      <h1>Studio Sandbox</h1>
      <p>
        This is the app the coding agent edits. Ask it in the chat to build
        something.
      </p>
    </main>
  );
};

import { defineConfig } from "vite";
import react from "@vitejs/plugin-react";

// Dev/preview server is reachable from the studio app's preview iframe via the
// sandbox host (*.e2b.app). Port 5175 is the convention the future preview wiring
// will look for.
export default defineConfig({
  server: {
    host: "0.0.0.0",
    port: 5175,
    strictPort: true,
    allowedHosts: [".e2b.app"],
  },
  preview: {
    host: "0.0.0.0",
    port: 5175,
    strictPort: true,
    allowedHosts: [".e2b.app"],
  },
  plugins: [react()],
});

