            </span>
            <span className="tabular-nums">{formatElapsed(elapsed)}</span>
          </div>
          {turn.steps.length > 0 ? (
            <div className="rounded-md border border-border bg-muted/30 p-2">
              {turn.steps.map(step => (
                <StepRow key={step.id} step={step} />
              ))}
            </div>
          ) : null}
        </div>
      )}
