type LipsyncSegment = { id: string; video: string; audio: string };

type LipsyncJob = {
  id: string;
  requestId: string;
  status: "pending" | "completed";
  outputPath?: string;
};

type LipsyncBody = { segments?: LipsyncSegment[]; model?: string };
type LipsyncState = { jobs: LipsyncJob[] };

